import{ApiClientBase,onReady,renderActivities,renderChart}from './shared/api-client.js';import{formatCurrencyVN}from './services/core-utils.js';import{invoices,clients,campaigns,deals,activities}from './supabase.js';class DashboardClient extends ApiClientBase{constructor(){super({moduleName: 'Dashboard',supabase:{invoices,clients,campaigns,deals,activities},demoDataFn: getDemoDashboardData});}async loadDashboardData(){return this.load('dashboard',async()=>{const [ invoiceStats,clientList,campaignStats,dealStats,recentActivities ]=await Promise.all([ this.supabase.invoices.getStats(),this.supabase.clients.getAll(),this.supabase.campaigns.getStats(),this.supabase.deals.getPipelineStats(),this.supabase.activities.getRecent(5)]);const totalRevenue=invoiceStats.data?.paid||0;const revenueGrowth=12.5;const activeClients=clientList.data?.length||0;const newClientsThisWeek=2;const totalLeads=campaignStats.data?.totalLeads||0;const activeCampaigns=campaignStats.data?.active||0;const totalCampaigns=campaignStats.data?.total||1;const systemHealth=totalCampaigns>0 ?(activeCampaigns/totalCampaigns*100).toFixed(1): 100;return{revenue:{value: totalRevenue,growth: revenueGrowth},clients:{value: activeClients,new: newClientsThisWeek},marketing:{value: totalLeads,label: 'Total Leads'},health:{value: systemHealth,label: 'Active Campaign Rate'},recentActivities: recentActivities.data||[],raw:{invoiceStats,campaignStats,dealStats}};});}async bindDashboard(){const data=await this.loadDashboardData();this.bind({'stat-revenue': formatCurrencyVN(data.revenue.value),'stat-clients': data.clients.value,'stat-impressions': data.marketing.value,'stat-health': `${data.health.value}%`});if(data.marketing.label!=='Ad Impressions'){const impVal=this.$('stat-impressions');if(impVal&&impVal.previousElementSibling){impVal.previousElementSibling.innerText=data.marketing.label;}}if(data.health.label!=='System Health'){const healthVal=this.$('stat-health');if(healthVal&&healthVal.previousElementSibling){healthVal.previousElementSibling.innerText=data.health.label;}}renderActivities(data.recentActivities,'live-activity-list');renderChart('revenueChart','revenue',data.raw?.invoiceStats?.data||null);return data;}}function getDemoDashboardData(){return{revenue:{value: 2400000000,growth: 12.5},clients:{value: 142,new: 8},marketing:{value: 8500000,label: 'Ad Impressions'},health:{value: 99.9,label: 'System Health'},recentActivities: [],raw: null};}const dashboardClient=new DashboardClient();onReady(async()=>{setTimeout(async()=>{await dashboardClient.bindDashboard();},100);});export{dashboardClient,DashboardClient};